// Try symbol-based parsing first
var lastChar = input[^1];
if (UnitPrefixes.TryGetValue(lastChar, out _))
{
    var numericPart = input[..^1].Trim();
    if (double.TryParse(numericPart, out var value))
    {
        var exponent = GetExponentForSymbol(lastChar);
        return value * PowersOf10[exponent];
    }
}

// Try name-based parsing: find a known prefix name and replace it with its symbol
foreach (var kvp in NameToSymbol)
{
    var nameIndex = input.IndexOf(kvp.Key, StringComparison.Ordinal);
    if (nameIndex >= 0)
    {
        var numericPart = string.Concat(input.AsSpan(0, nameIndex), input.AsSpan(nameIndex + kvp.Key.Length));
        var rebuilt = $"{numericPart.Trim()}{kvp.Value}";
        return rebuilt.FromMetric();
    }
}

