/// <summary>
/// Replaces metric prefix names with their corresponding symbols in the input string.
/// </summary>
/// <param name="input">The string containing metric prefix names.</param>
/// <returns>The string with prefix names replaced by symbols, or the original if no match.</returns>
private static string ReplaceNameBySymbol(string input)
{
    foreach (var kvp in NameToSymbol)
    {
        var idx = input.IndexOf(kvp.Key, StringComparison.Ordinal);
        if (idx >= 0)
        {
            return string.Concat(
                input.AsSpan(0, idx),
                SymbolStrings[kvp.Value].AsSpan(),
                input.AsSpan(idx + kvp.Key.Length));
        }
    }

    return input;
}

private static char? GetSymbolForExponent(int exponent) =>
    ExponentToSymbol.TryGetValue(exponent, out var symbol) ? symbol : null;

